import os
import time
import json
import pickle
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import hashlib

app = Flask(__name__)

class SecureCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        os.makedirs(cache_dir, exist_ok=True)
    
    def _get_cache_key(self, url, params):
        key_string = f"{url}_{json.dumps(params, sort_keys=True)}"
        return hashlib.md5(key_string.encode()).hexdigest()
    
    def _is_expired(self, timestamp, ttl):
        return time.time() > timestamp + ttl
    
    def _serialize_data(self, data):
        # Use JSON for serialization to avoid pickle security issues
        return json.dumps(data, separators=(',', ':'))
    
    def _deserialize_data(self, data_str):
        # Use JSON for deserialization to avoid pickle security issues
        return json.loads(data_str)
    
    def get(self, url, params=None):
        cache_key = self._get_cache_key(url, params or {})
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'r') as f:
                cache_data = json.load(f)
            
            if self._is_expired(cache_data['timestamp'], cache_data['ttl']):
                os.remove(cache_file)
                return None
            
            return cache_data['data']
        except (json.JSONDecodeError, KeyError, IOError):
            return None
    
    def set(self, url, data, params=None, ttl=None):
        cache_key = self._get_cache_key(url, params or {})
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        ttl = ttl or self.default_ttl
        
        cache_data = {
            'timestamp': time.time(),
            'ttl': ttl,
            'data': data
        }
        
        try:
            with open(cache_file, 'w') as f:
                json.dump(cache_data, f, separators=(',', ':'))
            return True
        except IOError:
            return False

# Initialize cache
